import{_ as t,o as e,c as p,Q as o}from"./chunks/framework.3daba8ea.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/业务框架/DTM/SAGA.md","filePath":"packages/doc/src/业务框架/DTM/SAGA.md","lastUpdated":1702458087000}'),a={name:"doc/业务框架/DTM/SAGA.md"},r=o('<p><strong>1.定义：</strong></p><p>1.长事务拆分为多个子事务</p><p>2.子事务除了有正向操作，还得提供逆向操作的方法（用于失败回退）</p><p>2.流程图</p><p>​ <img src="https://note.youdao.com/yws/public/resource/5c59dbf2a63c87df200525671e7ef119/xmlnote/FFE0D5FED4F3439596DE61D3A9F54324/30344" alt="0"></p><p>App应用程序，微服务1，微服务2，TM事务管理器</p><p>3.并发：子事务之间是串行执行，暂时没有实现并行执行。</p><p>4.恢复策略采用简单的逆向操作进行恢复。</p><p>5.高级SAGA</p><p><strong>6.逆向操作出现失败</strong></p><p>理论上逆向操作不允许出现失败，若逆向操作出现异常，属于临时故障或BUG，DTM会不断重试直到成功。为了避免程序bug导致补偿操作一直无法成功，建议开发者对全局事务表进行监控，发现重试超过3次的事务，发出报警，由运维人员找开发手动处理，参见<a href="https://www.dtm.pub/deploy/maintain.html" target="_blank" rel="noreferrer">dtm的运维</a></p><p><strong>7.特点</strong></p><p>用户需要提供action/compensate，不锁数据，并发较高。同时所有的事务状态存储在服务器，程序崩溃不会导致回滚。</p>',13),s=[r];function c(n,_,d,i,l,m){return e(),p("div",null,s)}const g=t(a,[["render",c]]);export{f as __pageData,g as default};
